export default function App() {
  // Global State
  const [user, setUser] = useState<any>(null);
  const [userData, setUserData] = useState<any>(null);
  const [view, setView] = useState('auth'); // auth, dashboard, library, quiz, shooter, playground, pet, teacher
  const [activeQuest, setActiveQuest] = useState<Quest | null>(null);
  const [loading, setLoading] = useState(true);
  const [authError, setAuthError] = useState<string | null>(null);

  // Auth Inputs
  const [authName, setAuthName] = useState('');
  const [authGrade, setAuthGrade] = useState(1);
  const [authAvatar, setAuthAvatar] = useState(AVATARS[0]);

  // --- INITIALIZATION ---
  useEffect(() => {
    const initAuth = async () => {
      try {
        const initialToken = (globalThis as any).__initial_auth_token;
        if (initialToken) await signInWithCustomToken(auth, initialToken);
        else await signInAnonymously(auth);
      } catch (err: any) {
        if (err.code === 'auth/admin-restricted-operation') setAuthError("Anonymous Auth Disabled in Firebase Console.");
        else setAuthError(err.message);
        setLoading(false);
      }
    };
    initAuth();

    return onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (u) {
        const ref = doc(db, 'artifacts', appId, 'users', u.uid, 'profile', 'main');
        const unsub = onSnapshot(ref, (s) => {
          if (s.exists()) {
            setUserData(s.data());
            if (view === 'auth') setView('dashboard');
          } else {
            setUserData(null);
            setView('auth');
          }
          setLoading(false);
        });
        return () => unsub();
      } else {
        setUserData(null);
        setView('auth');
        setLoading(false);
      }
    });
  }, [view]);

  // --- CORE ACTIONS ---
  const createProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    const profile = {
      username: authName || 'Kiddo', grade: authGrade, avatar: authAvatar,
      stars: 100, energy: 100, xp: 0, completedQuests: [], playgroundItems: [],
      pet: { name: 'Sparky', hunger: 80, fun: 80, energy: 80, xp: 0, level: 1 },
      missions: generateDailyMissions()
    };
    await setDoc(doc(db, 'artifacts', appId, 'users', user.uid, 'profile', 'main'), profile);
  };

  const generateDailyMissions = () => [
    { id: 'm1', text: 'Complete 1 Quiz', reward: 20, done: false },
    { id: 'm2', text: 'Feed your Pet', reward: 10, done: false },
    { id: 'm3', text: 'Play Math Shooter', reward: 30, done: false }
  ];

  const updateStats = async (stars: number, energy: number, xp: number, missionId?: string) => {
    if (!user) return;
    const ref = doc(db, 'artifacts', appId, 'users', user.uid, 'profile', 'main');

    let updates: any = {
      stars: increment(stars),
      energy: increment(energy),
      xp: increment(xp),
      'pet.xp': increment(Math.floor(xp / 2)) // Pet grows as you learn
    };

    if (missionId) {
      const missionIdx = userData.missions.findIndex((m: any) => m.id === missionId);
      if (missionIdx !== -1 && !userData.missions[missionIdx].done) {
        const newMissions = [...userData.missions];
        newMissions[missionIdx].done = true;
        updates.missions = newMissions;
        updates.stars = increment(stars + newMissions[missionIdx].reward); // Bonus
        alert(`🎯 Mission Complete! +${newMissions[missionIdx].reward} Bonus Stars!`);
      }
    }
    await updateDoc(ref, updates);
  };

  // --- RENDERERS ---
  if (loading && !authError) return <div className="h-screen flex items-center justify-center bg-indigo-50"><div className="animate-spin text-6xl">🎡</div></div>;

  if (authError) return <ErrorScreen error={authError} />;

  if (view === 'auth') return <AuthScreen {...{ authName, setAuthName, authGrade, setAuthGrade, authAvatar, setAuthAvatar, createProfile, AVATARS }} />;

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-24 md:pb-0 text-slate-800">
      <Header userData={userData} setView={setView} signOut={() => auth.signOut()} />

      <main className="max-w-7xl mx-auto p-4 md:p-6">
        {view === 'dashboard' && <Dashboard userData={userData} setView={setView} />}
        {view === 'library' && <Library userData={userData} setActiveQuest={setActiveQuest} setView={setView} />}
        {view === 'playground' && <Playground userData={userData} db={db} user={user} />}
        {view === 'pet' && <PetCenter userData={userData} db={db} user={user} />}
        {view === 'teacher' && <TeacherDashboard userData={userData} />}
        {view === 'quiz' && activeQuest && <QuizGame quest={activeQuest} onComplete={(s: number, t: number) => { updateStats(s >= Math.ceil(t / 2) ? activeQuest.rewardStars : 5, -10, s * 10, 'm1'); setView('dashboard'); }} onExit={() => setView('library')} />}
        {view === 'shooter' && <MathShooterGame onComplete={(score: number) => { updateStats(Math.floor(score / 2), -15, score * 5, 'm3'); setView('dashboard'); }} onExit={() => setView('dashboard')} />}
        {view === 'memory' && <MemoryMatchGame onComplete={(moves: number) => { updateStats(20, -10, 50); setView('dashboard'); }} onExit={() => setView('dashboard')} />}
        {view === 'scramble' && <WordScrambleGame onComplete={(score: number) => { updateStats(15, -5, score); setView('dashboard'); }} onExit={() => setView('dashboard')} />}
      </main>

      <MobileNav view={view} setView={setView} />
    </div>
  );
}

