// 7. QUIZ GAME ENGINE 🧩 (Simple reusable component)
function QuizGame({ quest, onComplete, onExit }: any) {
  const [idx, setIdx] = useState(0);
  const [score, setScore] = useState(0);
  const [answered, setAnswered] = useState(false);

  const handleAnswer = (optIdx: number) => {
    setAnswered(true);
    if (optIdx === quest.questions[idx].correct) setScore(s => s + 1);
    setTimeout(() => {
      if (idx < quest.questions.length - 1) {
        setIdx(i => i + 1);
        setAnswered(false);
      } else {
        onComplete(score + (optIdx === quest.questions[idx].correct ? 1 : 0), quest.questions.length);
      }
    }, 1000);
  };

  const q = quest.questions[idx];
  return (
    <div className="max-w-2xl mx-auto mt-10">
      <div className="bg-white rounded-3xl shadow-2xl overflow-hidden border-4 border-indigo-100">
        <div className="bg-indigo-600 p-6 text-white flex justify-between items-center">
          <h3 className="font-black text-xl">{quest.title}</h3>
          <button onClick={onExit}><LogOut size={20} /></button>
        </div>
        <div className="p-8">
          <div className="mb-2 text-xs font-bold text-slate-400 uppercase">Question {idx + 1}/{quest.questions.length}</div>
          <h2 className="text-2xl font-black text-slate-800 mb-8">{q.q}</h2>
          <div className="grid gap-4">
            {q.options.map((opt: string, i: number) => (
              <button
                key={i}
                disabled={answered}
                onClick={() => handleAnswer(i)}
                className={`p-4 rounded-xl font-bold text-lg text-left transition-all ${answered
                  ? i === q.correct
                    ? 'bg-green-100 text-green-700 border-2 border-green-500'
                    : 'bg-red-50 text-red-300'
                  : 'bg-slate-50 hover:bg-blue-50 hover:pl-6'
                  }`}
              >
                {opt}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

