// 10. MEMORY MATCH GAME 🧠
function MemoryMatchGame({ onComplete, onExit }: any) {
  const [cards, setCards] = useState<any[]>([]);
  const [flipped, setFlipped] = useState<number[]>([]);
  const [solved, setSolved] = useState<number[]>([]);
  const [moves, setMoves] = useState(0);

  useEffect(() => {
    const symbols = ['🐶', '🐱', '🐭', '🐹', '🐰', '🦊', '🐻', '🐼'];
    const deck = [...symbols, ...symbols]
      .sort(() => Math.random() - 0.5)
      .map((emoji, id) => ({ id, emoji }));
    setCards(deck);
  }, []);

  const handleFlip = (id: number) => {
    if (flipped.includes(id) || solved.includes(id) || flipped.length === 2) return;
    const newFlipped = [...flipped, id];
    setFlipped(newFlipped);

    if (newFlipped.length === 2) {
      setMoves(m => m + 1);
      const [first, second] = newFlipped;
      if (cards[first].emoji === cards[second].emoji) {
        setSolved(prev => [...prev, first, second]);
        setFlipped([]);
        if (solved.length + 2 === cards.length) {
          setTimeout(() => onComplete(moves), 1000);
        }
      } else {
        setTimeout(() => setFlipped([]), 1000);
      }
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-indigo-900 flex flex-col items-center justify-center p-4">
      <div className="bg-white rounded-3xl p-8 max-w-lg w-full shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-black text-indigo-900">🧠 Memory Match</h2>
          <div className="flex gap-4">
            <span className="font-bold text-indigo-500">Moves: {moves}</span>
            <button onClick={onExit}><LogOut /></button>
          </div>
        </div>
        <div className="grid grid-cols-4 gap-4">
          {cards.map((card, i) => (
            <button
              key={i}
              onClick={() => handleFlip(i)}
              className={`aspect-square text-4xl flex items-center justify-center rounded-xl transition-all transform ${flipped.includes(i) || solved.includes(i)
                ? 'bg-indigo-500 text-white rotate-0'
                : 'bg-indigo-100 text-transparent rotate-180 hover:bg-indigo-200'
                }`}
            >
              {card.emoji}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

